import{_ as a,o as t,c as o,a2 as r}from"./chunks/framework.DvFsUg-r.js";const p=JSON.parse('{"title":"Agent Core","description":"","frontmatter":{"title":"Agent Core","feature_id":"001","status":"planned","created":"2026-05-30 10:27 (KST)","tags":["agent","langgraph4j","spring-ai"]},"headers":[],"relativePath":"specs/001-agent-core/spec.md","filePath":"specs/001-agent-core/spec.md","lastUpdated":null}'),n={name:"specs/001-agent-core/spec.md"};function i(l,e,s,c,d,h){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="spec-agent-core" tabindex="-1">Spec: Agent Core <a class="header-anchor" href="#spec-agent-core" aria-label="Permalink to &quot;Spec: Agent Core&quot;">​</a></h1><h2 id="why-문제-목적" tabindex="-1">Why (문제 / 목적) <a class="header-anchor" href="#why-문제-목적" aria-label="Permalink to &quot;Why (문제 / 목적)&quot;">​</a></h2><p>사용자 요청을 받아 LLM 으로 계획을 세우고, 필요 시 도구를 호출하며, 결과를 종합해 응답하는 기본 ReAct 형 에이전트 루프가 필요하다. 이후 모든 기능(RAG, 멀티 에이전트 등)이 이 코어 위에 쌓인다.</p><h2 id="what-범위" tabindex="-1">What (범위) <a class="header-anchor" href="#what-범위" aria-label="Permalink to &quot;What (범위)&quot;">​</a></h2><ul><li>포함: 단일 에이전트 plan→act 루프, REST 진입점, 그래프 실행 추적</li><li>제외(Non-goals): 멀티 에이전트, 영속 메모리, 인증</li></ul><h2 id="user-scenarios" tabindex="-1">User Scenarios <a class="header-anchor" href="#user-scenarios" aria-label="Permalink to &quot;User Scenarios&quot;">​</a></h2><ol><li>As an API 사용자, I want <code>/api/agent/invoke</code> 에 질의를 보내면, so that 에이전트가 도구를 적절히 사용해 답을 돌려준다.</li></ol><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><ul><li>FR-1: StateGraph 는 <code>plan</code> 과 <code>act</code> 노드를 가지며 조건부 라우팅으로 순환한다.</li><li>FR-2: 도구 미필요 시 즉시 종료(END)한다.</li><li>FR-3: 각 노드 실행은 actuator/metrics 로 관측 가능하다.</li></ul><h2 id="contracts" tabindex="-1">Contracts <a class="header-anchor" href="#contracts" aria-label="Permalink to &quot;Contracts&quot;">​</a></h2><ul><li>Endpoint: <code>POST /api/agent/invoke</code> body <code>{ &quot;input&quot;: &quot;...&quot; }</code></li><li>Graph: <code>START → plan → (act → plan)* → END</code></li></ul><h2 id="open-questions" tabindex="-1">Open Questions <a class="header-anchor" href="#open-questions" aria-label="Permalink to &quot;Open Questions&quot;">​</a></h2><ul><li>[ ] 도구 목록 1차 범위는?</li><li>[ ] 최대 루프 횟수 제한값?</li></ul>',13)])])}const q=a(n,[["render",i]]);export{p as __pageData,q as default};
